import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./mentorDashboard.css";

const MentorDashboard = () => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState("overview");

  const [mentorData, setMentorData] = useState({});
  const [requests, setRequests] = useState([]);
  const [accepted, setAccepted] = useState([]);
  const [error, setError] = useState("");

  // Form fields for new specialization & slot
  const [newSpec, setNewSpec] = useState("");
  const [newDay, setNewDay] = useState("");
  const [newStart, setNewStart] = useState("");
  const [newEnd, setNewEnd] = useState("");

  const mentor_id = 1; // ⚠️ Replace with mentor ID from JWT/localStorage later
  const token = localStorage.getItem("token");

  /* ========== FETCH FUNCTIONS ========== */

  useEffect(() => {
    fetchOverview();
    fetchRequests();
    fetchAccepted();
  }, []);

  const fetchOverview = async () => {
    try {
      const res = await fetch(`http://localhost:5050/api/mentor/overview/${mentor_id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      setMentorData(data);
    } catch {
      setError("Failed to load mentor overview");
    }
  };

  const fetchRequests = async () => {
    try {
      const res = await fetch(`http://localhost:5050/api/mentor/requests/${mentor_id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      setRequests(data);
    } catch {
      setError("Failed to load mentor requests");
    }
  };

  const fetchAccepted = async () => {
    try {
      const res = await fetch(`http://localhost:5050/api/mentor/accepted/${mentor_id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const data = await res.json();
      setAccepted(data);
    } catch {
      setError("Failed to load accepted students");
    }
  };

  /* ========== ACTION HANDLERS ========== */

  const handleLogout = () => {
    localStorage.clear();
    navigate("/login");
  };

  const handleDecision = async (id, status) => {
    await fetch(`http://localhost:5050/api/mentor/requests/update/${id}`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({ status }),
    });
    fetchRequests();
    fetchAccepted();
  };

  const handleAddSpec = async () => {
    if (!newSpec.trim()) return;
    await fetch(`http://localhost:5050/api/mentor/specialization/${mentor_id}`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({ newSpecialization: newSpec }),
    });
    setNewSpec("");
    fetchOverview();
  };

  const handleAddSlot = async () => {
    if (!newDay || !newStart || !newEnd) return;
    await fetch(`http://localhost:5050/api/mentor/availability/${mentor_id}`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({
        day: newDay,
        start_time: newStart,
        end_time: newEnd,
      }),
    });
    setNewDay("");
    setNewStart("");
    setNewEnd("");
    fetchOverview();
  };

  /* ========== RENDER ========== */

  return (
    <div className="mentor-dashboard">
      {/* Header */}
      <div className="dashboard-header">
        <h1>Mentor Dashboard</h1>
        <button className="logout-btn" onClick={handleLogout}>
          Logout
        </button>
      </div>

      {/* Tabs */}
      <div className="mentor-tabs">
        <button
          onClick={() => setActiveTab("overview")}
          className={activeTab === "overview" ? "active" : ""}
        >
          Overview
        </button>
        <button
          onClick={() => setActiveTab("requests")}
          className={activeTab === "requests" ? "active" : ""}
        >
          Requests
        </button>
        <button
          onClick={() => setActiveTab("accepted")}
          className={activeTab === "accepted" ? "active" : ""}
        >
          Accepted Students
        </button>
      </div>

      {error && <p className="error">{error}</p>}

      {/* 🏠 Overview Tab */}
      {activeTab === "overview" && (
        <div className="overview-section">
          <h2>Welcome, {mentorData.facultyname || "Mentor"} 👋</h2>

          {/* Specializations */}
          <div className="mentor-card">
            <h3>Specializations</h3>
            <p>{mentorData.specialization || "No specialization listed yet"}</p>
            <div className="add-specialization">
              <input
                type="text"
                placeholder="Add new specialization"
                value={newSpec}
                onChange={(e) => setNewSpec(e.target.value)}
              />
              <button onClick={handleAddSpec}>Add</button>
            </div>
          </div>

          {/* Student Slots */}
          <div className="mentor-card">
            <h3>Student Slots</h3>
            <p>
              Accepted Students:{" "}
              <strong>{mentorData.accepted_students || 0}</strong> / 7
            </p>
            <p>
              Remaining Slots:{" "}
              <strong>
                {mentorData.remaining_slots >= 0
                  ? mentorData.remaining_slots
                  : 0}
              </strong>
            </p>
          </div>

          {/* Availability */}
          <div className="mentor-card">
            <h3>Availability Slots</h3>
            <table>
              <thead>
                <tr>
                  <th>Day</th>
                  <th>Start</th>
                  <th>End</th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {mentorData.availability?.length > 0 ? (
                  mentorData.availability.map((slot) => (
                    <tr key={slot.id}>
                      <td>{slot.day}</td>
                      <td>{slot.start_time}</td>
                      <td>{slot.end_time}</td>
                      <td>{slot.status}</td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="4">No availability slots added yet</td>
                  </tr>
                )}
              </tbody>
            </table>

            <div className="add-slot">
              <input
                type="date"
                value={newDay}
                onChange={(e) => setNewDay(e.target.value)}
              />
              <input
                type="time"
                value={newStart}
                onChange={(e) => setNewStart(e.target.value)}
              />
              <input
                type="time"
                value={newEnd}
                onChange={(e) => setNewEnd(e.target.value)}
              />
              <button onClick={handleAddSlot}>Add Slot</button>
            </div>
          </div>
        </div>
      )}

      {/* 📋 Requests Tab */}
      {activeTab === "requests" && (
        <div className="requests-section">
          <h2>Pending Requests</h2>
          {requests.length === 0 ? (
            <p>No pending requests</p>
          ) : (
            requests.map((r) => (
              <div key={r.id} className="request-card">
                <h3>{r.project_title}</h3>
                <p><strong>Student:</strong> {r.studentname}</p>
                <p><strong>Domain:</strong> {r.domain}</p>
                <p>{r.description}</p>
                <button
                  onClick={() => handleDecision(r.id, "accepted")}
                  className="accept-btn"
                >
                  Accept
                </button>
                <button
                  onClick={() => handleDecision(r.id, "rejected")}
                  className="reject-btn"
                >
                  Reject
                </button>
              </div>
            ))
          )}
        </div>
      )}

      {/* 👩‍🎓 Accepted Students Tab */}
      {activeTab === "accepted" && (
        <div className="accepted-section">
          <h2>Accepted Students</h2>
          {accepted.length === 0 ? (
            <p>No accepted students yet</p>
          ) : (
            accepted.map((a) => (
              <div key={a.id} className="accepted-card">
                <h3>{a.title}</h3>
                <p><strong>Student:</strong> {a.studentname}</p>
                <p><strong>Domain:</strong> {a.domain}</p>
                <p><strong>Status:</strong> {a.status}</p>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
};

export default MentorDashboard;
